linkList.script:
debugger
let col = arguments[1].column.label;
if(col === "名称") {
    let row = arguments[1].row;
    showEditFramePageDialog(row);
}

function showEditFramePageDialog(row) {
    debugger;
    const pageName = $Variable.模型编辑_框架页面_页面名称;
    const options = {
        type: 0, //替换式页面样式配置
        sTType: 2,
        spaceTime: $Variable.配置后台时空对象全路径, 
        variables: [{
                name: "配置后台对象名称",
                value: $Variable.配置后台对象名称
            },
            {
                name: "数字孪生建模时空仓库Name", //当前选中模型
                value: row.modelname
            },
            {
                name: "数字孪生建模时空仓库ID", //当前选中模型
                value: row.modelid
            },
            {
                name: "数字孪生建模时空仓库GUID", //当前选中模型
                value: row.modelguid
            },
            {
                name: "当前页面名称", //当前选中模型
                value: $Variable.模型编辑_框架页面_页面名称
            },
            {
                name: "工程时空仓库名称",
                value: $Variable.工程时空仓库名称
            },
            {
                name: "工程时空仓库ID",
                value: $Variable.工程时空仓库ID
            },
            {
                name: "工程时空仓库GUID",
                value: $Variable.工程时空仓库GUID
            },
            {
                name: "工程Root时空仓库名称",
                value: $Variable.工程Root时空仓库名称
            },
            {
                name: "工程Root时空仓库ID",
                value: $Variable.工程Root时空仓库ID
            },
            {
                name: "工程Root时空仓库GUID",
                value: $Variable.工程Root时空仓库GUID
            }, 
            {
                name: "配置后台时空对象全路径",
                value: $Variable.配置后台时空对象全路径
            },            
            {
                name: "模型根时空仓库GUID", 
                value: $Variable.模型根时空仓库GUID
            },
            // {
            //     name: "工厂模型根仓库名称", //当前选中模型
            //     value: $Variable.工厂模型根_时空仓库名称
            // },
        ]
    };
    ShowPage(pageName, options);
}
